-- Create "users" table
CREATE TABLE "users" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "first_name" character varying NOT NULL, "last_name" character varying NOT NULL, "middle_name" character varying NOT NULL, "display_name" character varying NOT NULL, "email_address" character varying NOT NULL, "phone_number" character varying NOT NULL, "avatar" character varying NOT NULL, "disabled" boolean NOT NULL DEFAULT false, "identification_number" character varying NOT NULL, "tier" smallint NOT NULL DEFAULT 0, PRIMARY KEY ("id"));
-- Create index "users_email_address_key" to table: "users"
CREATE UNIQUE INDEX "users_email_address_key" ON "users" ("email_address");
